      type: "api-call",
      api: {
        service: meta.apiCall.api.service,
        endpoint: meta.apiCall.api.endpoint,
        raw: meta.apiCall.api.raw,
        auth: meta.apiCall.api.requiresAuth,
        tags: meta.apiCall.api.tags
